<?php
namespace Zclone\services;
final class ResourceService { public function production(array $planet,array $buildings): array { $speed=(float)($planet['speed']??1); $m=(int)($buildings['metal_mine']??0); $c=(int)($buildings['crystal_mine']??0); $d=(int)($buildings['deuterium_synthesizer']??0); $solar=(int)($buildings['solar_plant']??0); return ['metal'=>30*$speed*$m*pow(1.12,$m)/3600,'crystal'=>20*$speed*$c*pow(1.11,$c)/3600,'deuterium'=>10*$speed*$d*pow(1.10,$d)/3600,'energy'=>20+floor(20*$solar*pow(1.1,$solar))]; } public function accrue(array $planet,array $buildings): array { $elapsed=max(0,time()-strtotime($planet['last_resource_at'] ?? 'now')); $p=$this->production($planet,$buildings); $cap=(float)($planet['storage_capacity']??100000); return ['metal'=>min($cap,(float)$planet['metal']+$p['metal']*$elapsed),'crystal'=>min($cap,(float)$planet['crystal']+$p['crystal']*$elapsed),'deuterium'=>min($cap,(float)$planet['deuterium']+$p['deuterium']*$elapsed),'energy'=>$p['energy']]; } }
